import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Manages tasks, assignments, and task status within projects.',

  dependencies: {
    modules: ['auth'], // Tasks depend on auth for user context
  },

  exposes: {
    routes: [
      // Existing routes (example, not explicitly requested but good to show context)
      { method: 'GET', path: '/tasks', auth: true },
      { method: 'GET', path: '/tasks/:id', auth: true },
      { method: 'POST', path: '/tasks', auth: true },
      { method: 'PATCH', path: '/tasks/:id', auth: true },
      { method: 'DELETE', path: '/tasks/:id', auth: true },
      // New route for marking as read
      { method: 'POST', path: '/tasks/:id/mark-as-read', auth: true },
    ],
    functions: [
      'getTaskById',
      'createTask',
      'updateTask',
      'deleteTask',
      'markTaskAsRead', // Expose the new service function
    ],
    types: ['Task', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: tasks table',
    'reads from: users table (for authorization)',
  ],

  invariants: [
    'A task must always belong to exactly one project',
    'Only team members can view or modify tasks within their team\'s projects',
    'Marking a task as read must be idempotent',
  ],
});
