import { query } from '~/lib/db';
import { Task } from '~/modules/tasks/types';

/**
 * Updates the 'read' status of a specific task.
 * This operation is idempotent: setting 'read' to true when it's already true
 * will not cause an error or change the state.
 *
 * @param taskId The ID of the task to update.
 * @param userId The ID of the user performing the action (for authorization/ownership checks).
 * @returns The updated task, or null if not found/unauthorized.
 */
export async function updateTaskReadStatus(
  taskId: string,
  userId: string,
): Promise<Task | null> {
  // In a real application, you'd also check if the userId has permission
  // to modify this task (e.g., belongs to the same team/project).
  // For this example, we'll assume the `requireUser` check in the route
  // is sufficient for basic authentication, and a more granular check
  // would happen here if needed.

  const result = await query<Task>(
    `
    UPDATE tasks
    SET read = TRUE, updated_at = NOW()
    WHERE id = $1
    RETURNING id, project_id, title, description, status, assigned_to_user_id, created_at, updated_at, read;
    `,
    [taskId]
  );

  return result.rows[0] || null;
}
