```aether:modules/tasks/services/tasks.ts
import { ok, err, Result } from '~/lib/result';
import { updateTaskReadStatus } from '~/modules/tasks/lib/queries';
import { Task, TaskError } from '~/modules/tasks/types';

/**
 * Service function to mark a task as read.
 * Encapsulates the business logic for updating the task's read status.
 *
 * @param taskId The ID of the task to mark as read.
 * @param userId The ID of the user performing the action.
 * @returns A Result indicating success with the updated task, or an error.
 */
export async function markTaskAsRead(
  taskId: string,
  userId: string,
): Promise<Result<Task, TaskError>> {
  const updatedTask = await updateTaskReadStatus(taskId, userId);

  if (!updatedTask) {
    // This could mean the task doesn't exist or the user doesn't have permission.
    // For simplicity, we'll treat it as not found for now.
    return err({ type: 'NotFound', message: `Task with ID ${taskId} not found or inaccessible.` });
  }

  return ok(updatedTask);
}
