import { Request } from 'aether';
import { requireUser } from '~/lib/auth';
import { parseParams } from '~/lib/validate';
import { markTaskAsRead } from '~/modules/tasks/services/tasks';

/**
 * Handles the request to mark a specific task as read.
 *
 * @param req The incoming request object.
 * @returns A Response indicating success or failure.
 */
export async function markAsReadHandler(req: Request): Promise<Response> {
  // Auth is always explicit: Every authenticated route must call requireUser(req)
  const userResult = await requireUser(req);
  if (userResult.isErr()) {
    return new Response(JSON.stringify({ error: userResult.error.message }), {
      status: userResult.error.status,
      headers: { 'Content-Type': 'application/json' },
    });
  }
  const user = userResult.value;

  // Validate path parameters
  const paramsResult = parseParams(req, {
    id: 'string',
  });
  if (paramsResult.isErr()) {
    return new Response(JSON.stringify({ error: paramsResult.error.message }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }
  const { id: taskId } = paramsResult.value;

  // Call the service layer to perform the action
  const result = await markTaskAsRead(taskId, user.id);

  if (result.isErr()) {
    switch (result.error.type) {
      case 'NotFound':
        return new Response(JSON.stringify({ error: result.error.message }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' },
        });
      case 'Unauthorized':
        return new Response(JSON.stringify({ error: result.error.message }), {
          status: 403,
          headers: { 'Content-Type': 'application/json' },
        });
      case 'InvalidInput':
        return new Response(JSON.stringify({ error: result.error.message }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        });
      default:
        // Catch-all for unexpected errors, treat as internal server error
        console.error('Unexpected error marking task as read:', result.error);
        return new Response(JSON.stringify({ error: 'Internal server error' }), {
          status: 500,
          headers: { 'Content-Type': 'application/json' },
        });
    }
  }

  // Success response
  return new Response(JSON.stringify({
    message: 'Task marked as read successfully.',
    task: result.value,
  }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}
